{
  "domain_analysis": {
    "business_context": "E-commerce platform managing the full purchase lifecycle: browsing, cart management, checkout with inventory reservation, payment, and post-purchase refunds. The domain enforces inventory integrity, promotion exclusivity, and time-bound reservation and refund windows.",
    "bounded_context": "Order & Checkout",
    "ubiquitous_language": [
      { "term": "Cart", "definition": "A transient collection of items a customer intends to purchase. Items in the cart do not reserve inventory." },
      { "term": "Checkout", "definition": "The process initiated when a customer commits to purchasing cart contents. Triggers inventory reservation and starts the payment window." },
      { "term": "Inventory Reservation", "definition": "A time-limited hold on inventory units for a specific checkout session, lasting a maximum of 15 minutes. Prevents other customers from purchasing the same units during this window." },
      { "term": "Reservation Release", "definition": "The automatic return of reserved inventory units to available stock when a checkout session expires without payment." },
      { "term": "Promotion", "definition": "A platform-initiated pricing discount applied to a specific product. A product may have at most one active promotion at any time." },
      { "term": "Discount Code", "definition": "A customer-supplied code that grants a price reduction. Mutually exclusive with promotional pricing on the same order." },
      { "term": "Payment Confirmation", "definition": "The irreversible event marking successful payment. After this point, the order becomes immutable." },
      { "term": "Order", "definition": "The finalized record of a purchase after payment confirmation. Cannot be modified once payment is confirmed." },
      { "term": "Refund Window", "definition": "The 30-day period after delivery during which a customer may request a refund." },
      { "term": "Listed Product", "definition": "A product visible in the catalog. Listing status is independent of inventory availability; a product may be listed with zero inventory." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "Adding items to a cart does NOT reserve inventory. Inventory remains available to all customers until checkout begins.",
      "invariant": true,
      "invariant_justification": "Premature reservation would corrupt inventory counts and create phantom holds, leading to system-wide data inconsistency.",
      "testable_assertion": "When a customer adds an item to their cart, the product's available inventory count must not decrease."
    },
    {
      "id": "BR-2",
      "rule": "Inventory is reserved only when checkout begins, reducing available stock by the quantity being purchased.",
      "invariant": true,
      "invariant_justification": "Without reservation at checkout, two customers could simultaneously pay for the last unit, resulting in overselling and corrupt inventory state.",
      "testable_assertion": "When checkout is initiated for N units of a product, available inventory for that product must decrease by exactly N and a reservation record must be created."
    },
    {
      "id": "BR-3",
      "rule": "If payment is not completed within 15 minutes of checkout initiation, the reservation is automatically released and inventory is returned to available stock.",
      "invariant": false,
      "invariant_justification": "The 15-minute window is a business policy decision. A VP could adjust this to 10 or 30 minutes without corrupting system state.",
      "testable_assertion": "A checkout session that has not received payment confirmation within 15 minutes must have its reservation released and available inventory restored to pre-checkout levels."
    },
    {
      "id": "BR-4",
      "rule": "A product can have at most one active promotion at any given time.",
      "invariant": true,
      "invariant_justification": "Multiple concurrent promotions on the same product would create ambiguity about the correct price, leading to inconsistent pricing state and potential revenue loss or customer disputes.",
      "testable_assertion": "At any point in time, querying active promotions for a single product must return zero or one result, never more."
    },
    {
      "id": "BR-5",
      "rule": "Discount codes and promotional pricing are mutually exclusive per order. Only one discount mechanism may apply.",
      "invariant": true,
      "invariant_justification": "Allowing stacking of discount mechanisms would produce incorrect pricing that violates the intended margin floor. This is a pricing integrity constraint.",
      "testable_assertion": "An order must never have both a discount code applied AND promotional pricing active. If a product has an active promotion and a discount code is submitted, the system must apply exactly one and reject or ignore the other."
    },
    {
      "id": "BR-6",
      "rule": "Orders cannot be modified after payment is confirmed.",
      "invariant": true,
      "invariant_justification": "Post-payment modification would break the financial audit trail and could cause inconsistency between what was charged and what is fulfilled. This is a data integrity and accounting constraint.",
      "testable_assertion": "Any attempt to change order line items, quantities, shipping address, or applied discounts after payment confirmation must be rejected by the system."
    },
    {
      "id": "BR-7",
      "rule": "A product with zero available inventory cannot be purchased, regardless of its listing status in the catalog.",
      "invariant": true,
      "invariant_justification": "Allowing purchase of zero-inventory items would result in overselling — a fundamental inventory integrity violation that creates fulfillment obligations the business cannot meet.",
      "testable_assertion": "When a customer initiates checkout for a product with zero available inventory, the system must reject the checkout and must not create a reservation."
    },
    {
      "id": "BR-8",
      "rule": "Refund requests must be submitted within 30 days of the delivery date. Requests outside this window are rejected.",
      "invariant": false,
      "invariant_justification": "The 30-day refund window is a business policy that could be changed by management (e.g., extended to 60 days for holidays) without corrupting system state.",
      "testable_assertion": "A refund request submitted on day 31 or later after delivery must be rejected. A refund request on day 30 or earlier must be accepted for processing."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A product with 5 units of available inventory",
      "when": "A customer adds 2 units of that product to their cart",
      "then": "The available inventory remains at 5 units and no reservation is created"
    },
    {
      "id": "AC-2",
      "given": "A product with 5 units of available inventory and 2 units in a customer's cart",
      "when": "The customer initiates checkout",
      "then": "A reservation is created for 2 units, and available inventory decreases to 3 units"
    },
    {
      "id": "AC-3",
      "given": "An active checkout session with a reservation for 2 units created 15 minutes ago",
      "when": "The reservation expiry timer fires and no payment has been received",
      "then": "The reservation is released, available inventory increases by 2, and the checkout session is marked as abandoned"
    },
    {
      "id": "AC-4",
      "given": "A product with an active promotion offering 20% off",
      "when": "An admin attempts to create a second promotion for the same product",
      "then": "The system rejects the second promotion and returns an error indicating only one active promotion is allowed per product"
    },
    {
      "id": "AC-5",
      "given": "An order containing a product with an active 20% promotion",
      "when": "The customer applies a discount code at checkout",
      "then": "Only one discount mechanism is applied to the order; the system does not stack the promotional pricing with the discount code"
    },
    {
      "id": "AC-6",
      "given": "An order with payment confirmed",
      "when": "The customer or an admin attempts to modify the order (change quantity, add items, change address)",
      "then": "The modification is rejected and the order remains unchanged"
    },
    {
      "id": "AC-7",
      "given": "A product listed in the catalog with zero available inventory",
      "when": "A customer attempts to initiate checkout for that product",
      "then": "Checkout is rejected with a clear out-of-stock message and no reservation is created"
    },
    {
      "id": "AC-8",
      "given": "An order delivered 29 days ago",
      "when": "The customer submits a refund request",
      "then": "The refund request is accepted and enters the refund processing workflow"
    },
    {
      "id": "AC-9",
      "given": "An order delivered 31 days ago",
      "when": "The customer submits a refund request",
      "then": "The refund request is rejected with a message indicating the 30-day refund window has expired"
    },
    {
      "id": "AC-10",
      "given": "A product with 1 unit of available inventory and two customers with it in their carts",
      "when": "Both customers initiate checkout simultaneously",
      "then": "Exactly one customer receives a reservation; the other is rejected with an out-of-stock error. Available inventory reaches zero, never goes negative."
    },
    {
      "id": "AC-11",
      "given": "A checkout session with a reservation that was released due to the 15-minute timeout",
      "when": "The customer attempts to submit payment for the expired session",
      "then": "Payment is rejected and the customer is informed the checkout session has expired"
    },
    {
      "id": "AC-12",
      "given": "An order delivered exactly 30 days ago",
      "when": "The customer submits a refund request",
      "then": "The refund request is accepted (the 30-day window is inclusive of day 30)"
    }
  ],

  "edge_cases": [
    {
      "scenario": "Customer begins checkout, inventory is reserved, then the product's last units are also added to another customer's cart. The first customer abandons checkout after 15 minutes.",
      "expected_behavior": "Reservation is released, inventory becomes available again. The second customer can now proceed to checkout if they initiate it before another customer does."
    },
    {
      "scenario": "A discount code is applied to an order where some products have active promotions and some do not.",
      "expected_behavior": "The mutual exclusivity rule applies per order: either the discount code or promotional pricing is applied, not both. The spec says 'per order,' so the system must choose one mechanism for the entire order."
    },
    {
      "scenario": "Inventory drops to zero between when a customer adds an item to the cart and when they initiate checkout.",
      "expected_behavior": "Checkout initiation is rejected with an out-of-stock error. Cart contents are informational only; they confer no inventory rights."
    },
    {
      "scenario": "Payment gateway confirms payment after the 15-minute reservation has expired and inventory has been released.",
      "expected_behavior": "The system must reject or reverse the late payment. The reservation no longer exists, so the fulfillment obligation cannot be met. This is a critical race condition that requires careful handling."
    },
    {
      "scenario": "Customer requests a refund but delivery date is disputed (e.g., carrier says delivered, customer says not received).",
      "expected_behavior": "The 30-day clock starts from the recorded delivery date. Delivery disputes are a separate concern but affect the refund window calculation."
    },
    {
      "scenario": "An active promotion on a product expires exactly at the moment a customer initiates checkout.",
      "expected_behavior": "The price at checkout initiation should be deterministic — the system must lock the price at reservation time and honor it through payment, even if the promotion expires during the 15-minute window."
